// // 2.7.3 | 2022-05-13 | raj | STRY0118971 - Technical Story: Fix Script to "Recount" Template Schedules
// Script Continued Below
// set test variable to true to run a test of the count fix script
var test = false;

update_template_schedule_count();


function update_template_schedule_count(){
	var countChangedTemplates = 0;
	var countTemplates = 0;

	var grProcessTemplate = new GlideRecord('x_153465_discovert_discover_routing_template');
	grProcessTemplate.query(); 
	while (grProcessTemplate.next()) { 
		countTemplates++;

		// Count Schedules AFTER insert / delete
		var gaSchedules = new GlideAggregate('x_153465_discovert_tasker_schedule');
		gaSchedules.addQuery('tasker_process', grProcessTemplate.getUniqueValue());
		gaSchedules.addAggregate('COUNT');
		gaSchedules.query();

		var numSchedules=0;
		if(gaSchedules.next()) {
			numSchedules = gaSchedules.getAggregate('COUNT');
			if(parseInt(grProcessTemplate.schedules) != numSchedules){
				var previousCount = grProcessTemplate.schedules;
				grProcessTemplate.schedules = numSchedules;
				grProcessTemplate.setWorkflow(false); // do not trigger business rules/workflows
				grProcessTemplate.autoSysFields(false); // do not update system fields

				if(!test){
					var msg = 'Tasker 2.7.3 - Fix Temp Schedule Count - Change Template Schedule Count - for Template: ' +
						grProcessTemplate.template_name + ' count from: (' + previousCount + ') to (' + numSchedules + ')';
					grProcessTemplate.update(msg);
					gs.info(msg);
				}
				countChangedTemplates++;
			}
		}		
	}
	if(test){
		gs.info('Tasker 2.7.3 - Fix Temp Schedule Count - TEST RUN TO SHOW COUNTS - found (' + countTemplates + ') templates in System. ('+ countChangedTemplates + ') have the wrong count for template schedules.  Change "test" variable to false in the Fix Script  to update the schedule counts for ('+ countChangedTemplates + ') templates.');
	}else{
		gs.info('Tasker 2.7.3 - Fix Temp Schedule Count - found (' + countTemplates + ') Templates in System. ('+ countChangedTemplates + ') had the wroung schedule count before fix script run.  ('+ countChangedTemplates + ') were updated to correct the counts.');
	}
}
